{"code": "import json
import re
import os
from collections import defaultdict

# Get businesses that accept credit cards
credit_card_businesses = locals()['var_functions.query_db:60']

print('Total businesses accepting credit cards:', len(credit_card_businesses))

# Extract categories from descriptions
category_counts = defaultdict(int)
business_to_categories = {}

for business in credit_card_businesses:
    business_id = business['business_id']
    description = business.get('description', '')

    categories = []

    # Pattern 1: "services in X, Y, Z"
    if 'services in' in description:
        match = re.search(r'services in (.+?)(?:\.|, this|, and)', description)
        if match:
            cats = [c.strip() for c in match.group(1).split(',') if c.strip()]
            categories.extend(cats)

    # Pattern 2: "including X, Y, Z"
    if 'including' in description:
        match = re.search(r'including (.+?)(?:\.|, located)', description, re.IGNORECASE)
        if match:
            cats = [c.strip() for c in match.group(1).split(',') if c.strip()]
            categories.extend(cats)

    # Clean categories
    cleaned = []
    for cat in categories:
        cat = cat.strip()
        if cat.startswith('and '):
            cat = cat[4:]
        if cat and len(cat) > 2:
            cleaned.append(cat)

    if not cleaned:
        cleaned = ['General Business']

    business_to_categories[business_id] = cleaned
    for cat in cleaned:
        category_counts[cat] += 1

# Find top category
if category_counts:
    top_category = max(category_counts.items(), key=lambda x: x[1])
    print('Top category:', top_category)

    # Get business IDs for top category
    top_category_name = top_category[0]
    business_ids_in_top = []
    for bid, cats in business_to_categories.items():
        if top_category_name in cats:
            business_ids_in_top.append(bid)

    print('Businesses in top category:', len(business_ids_in_top))

    result = {
        'top_category': top_category_name,
        'business_count': top_category[1],
        'business_ids': business_ids_in_top
    }
else:
    result = {'error': 'No categories found'}

print('__RESULT__:')
print(json.dumps(result))"}
